import { useState } from 'react';

export default function RetroTubeClone() {
  const [videos, setVideos] = useState([
    {
      id: 1,
      title: "Cyber Café Perú 2005",
      channel: "RetroNet",
      views: "12,000 vistas",
      image: "https://images.unsplash.com/photo-1498050108023-c5249f4df085?q=80&w=1200&auto=format&fit=crop",
      video: "https://www.w3schools.com/html/mov_bbb.mp4",
      duration: "5:30"
    },
    {
      id: 2,
      title: "Motorola Java Portal",
      channel: "J2ME Perú",
      views: "8,400 vistas",
      image: "https://images.unsplash.com/photo-1518770660439-4636190af475?q=80&w=1200&auto=format&fit=crop",
      video: "https://www.w3schools.com/html/mov_bbb.mp4",
      duration: "3:45"
    },
    {
      id: 3,
      title: "Internet Cabina 2005",
      channel: "CabinaNet",
      views: "15,700 vistas",
      image: "https://images.unsplash.com/photo-1516321318423-f06f85e504b3?q=80&w=1200&auto=format&fit=crop",
      video: "https://www.w3schools.com/html/mov_bbb.mp4",
      duration: "7:20"
    }
  ]);

  const [searchTerm, setSearchTerm] = useState('');

  const filteredVideos = videos.filter(video =>
    video.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    video.channel.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleDelete = (id) => {
    setVideos(videos.filter(v => v.id !== id));
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-purple-900 via-fuchsia-800 to-red-700 text-white font-mono">
      {/* HEADER */}
      <header className="flex items-center justify-between px-6 py-4 border-b-4 border-pink-300 bg-gradient-to-r from-purple-900 to-pink-900 shadow-2xl sticky top-0 z-50">
        <div className="flex items-center gap-3">
          <div className="bg-pink-300 text-black w-10 h-10 rounded-md flex items-center justify-center font-bold text-lg border-2 border-white">
            R
          </div>
          <h1 className="text-3xl font-bold tracking-wide text-pink-300 drop-shadow-lg">RetroTube 2005</h1>
        </div>

        <input
          type="text"
          placeholder="Buscar videos..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="bg-white text-black border-4 border-pink-300 rounded-md px-5 py-2 w-[35%] outline-none shadow-lg focus:ring-2 focus:ring-pink-500"
        />

        <button className="bg-pink-400 hover:bg-pink-300 text-black transition px-5 py-2 rounded-md font-bold border-2 border-white shadow-lg">
          Subir
        </button>
      </header>

      {/* MAIN */}
      <main className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 p-6">
        {filteredVideos.length > 0 ? (
          filteredVideos.map((video) => (
            <div
              key={video.id}
              className="bg-gradient-to-br from-pink-100 to-purple-100 text-black rounded-md overflow-hidden border-4 border-pink-300 shadow-2xl hover:scale-105 transition duration-300"
            >
              {/* IMAGEN O VIDEO */}
              <div className="relative w-full h-52 bg-black overflow-hidden border-b-4 border-pink-300">
                <img
                  src={video.image}
                  alt={video.title}
                  className="w-full h-full object-cover"
                />
                <div className="absolute bottom-2 right-2 bg-black text-white px-2 py-1 text-xs font-bold rounded">
                  {video.duration}
                </div>
              </div>

              {/* INFO */}
              <div className="p-4 space-y-2">
                <h2 className="font-bold text-lg leading-tight text-black">
                  {video.title}
                </h2>

                <p className="text-purple-700 text-sm font-bold">
                  {video.channel}
                </p>

                <p className="text-gray-600 text-sm">{video.views}</p>

                {/* BOTONES */}
                <div className="flex gap-2 mt-3">
                  <button
                    onClick={() => window.open(video.video, '_blank')}
                    className="flex-1 bg-blue-600 hover:bg-blue-500 text-white py-2 rounded-md font-bold border-2 border-white transition"
                  >
                    Ver
                  </button>
                  <button
                    onClick={() => handleDelete(video.id)}
                    className="flex-1 bg-red-600 hover:bg-red-500 text-white py-2 rounded-md font-bold border-2 border-white transition"
                  >
                    🗑️ Eliminar
                  </button>
                </div>
              </div>
            </div>
          ))
        ) : (
          <div className="col-span-full text-center py-20">
            <p className="text-2xl text-pink-300 font-bold">No se encontraron videos</p>
          </div>
        )}
      </main>

      {/* FOOTER */}
      <footer className="border-t-4 border-pink-300 text-center text-pink-200 py-6 mt-10 bg-gradient-to-r from-red-800 via-purple-800 to-pink-700 font-bold">
        RetroTube Global • Plataforma retro de videos inspirada en el internet clásico 2005
      </footer>
    </div>
  );
}
